// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  video: VideoStore
  videoIdea: VideoIdeaStore
  comment: CommentStore
  analyticsSnapshot: AnalyticsSnapshotStore
  genre: GenreStore
  contentScript: ContentScriptStore
  uploadQueue: UploadQueueStore
  chatMessage: ChatMessageStore

  constructor() {
    this.user = new UserStore()
    this.video = new VideoStore()
    this.videoIdea = new VideoIdeaStore()
    this.comment = new CommentStore()
    this.analyticsSnapshot = new AnalyticsSnapshotStore()
    this.genre = new GenreStore()
    this.contentScript = new ContentScriptStore()
    this.uploadQueue = new UploadQueueStore()
    this.chatMessage = new ChatMessageStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.video.clear()
    this.videoIdea.clear()
    this.comment.clear()
    this.analyticsSnapshot.clear()
    this.genre.clear()
    this.contentScript.clear()
    this.uploadQueue.clear()
    this.chatMessage.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
